var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>카페 이벤트의 신기원을 열다!</color>\\n익명의 제보자","JPN":"<color=#ffd34c>カフェイベントに革新！</color>\\n匿名記者","ENG":"<color=#ffd34c>A New Era of Cafe Events!</color>\\nAn anonymous informant","TWN":"<color=#ffd34c>開啟咖啡廳活動的新紀元！</color>\\n匿名評論者"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"그라운드 원의 이색 테마 카페 스트레가에서 웨딩 시즌을 맞이하여 웨딩 이벤트를 개최했다.","JPN":"グラウンド・ワンの異色テーマカフェ「ストレガ」ではウェディングシーズンに合わせて、ウェディングイベントが開催された。","ENG":"The unique-themed Cafe Strega, in Ground One, has hosted a wedding-themed event in celebration of the marriage boom.","TWN":"G1一間風格獨特的咖啡廳史特雷加，配合結婚季舉辦一場特別的婚禮活動。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"오픈과 동시에 손님 모두 함께 참여할 수 있는 대단원의 연극이 시작되며, 종국의 결말로 치닫는다.","JPN":"オープンと同時に来店客全員が参加できる演劇が始まった。演劇は結末に向かって一気に駆け抜け、大団円で終わった。","ENG":"As the cafe opened its doors, a grand-scale play began, where all the customers could participate in as well. The play leads to a compelling finale and...","TWN":"進到咖啡廳後，便上演所有顧客都可以一起參與的大團圓戲劇，最後的結局也隨之而來。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"이후 카페 스트레가의 매출이 급격히 상승하여…….","JPN":"その後、カフェストレガの売上は急上昇し……","ENG":"This led to a significant increase in Cafe Strega's sales...","TWN":"這導致史特雷加咖啡廳的營業額大幅提升……"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"매출 장표? 그래프가 마음에 드나 봐?","JPN":"売上台帳？　グラフが気に入ったみたいね。","ENG":"Is that the sales account? Seems like you're happy with the graph.","TWN":"這是營業統計？看來你對這個圖表很滿意呢？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"당연히 마음에 들지. 이렇게 예쁜 수직 상승선을 본 기억이 또 있나 싶을 정도야.","JPN":"当然だろう。これほど美しい右肩上がりの線がはたしてあるだろうかと思うくらいだ。","ENG":"Of course I do. I've never seen a more upward-oriented line before.","TWN":"當然滿意，我都想不起來我曾經看過如此美麗的曲線圖。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 손님들도 웨딩 디저트에 만족하고 돌아간 것 같아서 기분이 좋네.","JPN":"ふふっ。お客さんもウェディングデザートに満足してお帰りになったようで嬉しいわ。","ENG":"Ha ha. And it seems the customers were also satisfied with the wedding desserts. I'm glad.","TWN":"呵呵，我也很開心，因為客人都非常滿意婚禮甜點。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"앞으로도 종종 할까?","JPN":"これからも、たまにやろうかしら？","ENG":"Should we do this regularly?","TWN":"以後也多辦些活動吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그런 끔찍한 소리는 하지도 마.","JPN":"そんな恐ろしいこと言うな。","ENG":"Don't even think about it.","TWN":"你想嚇死我嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"드레스며 디저트며 온통 난리였던 거 생각하면…… 꿈에서 나올까 무섭다고.","JPN":"ドレスといい、デザートといい、すべてがカオス状態だったし……夢に出てきそうだ。","ENG":"The dresses, the desserts, the mess... I'm going to have nightmares.","TWN":"一想到婚紗、甜點、還有這些騷動……我作夢都會怕。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"혹시 악몽 꾸게 되면 말해!","JPN":"もし悪夢を見るようになったら言ってよ！","ENG":"Tell me if you do!","TWN":"作惡夢的話記得找我！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"마담 클로에 스타시커가 만든 악몽에 용한 부적을 사둔 게 있으니까!","JPN":"マダム・クロエ・スターシーカーの作った悪夢に効くお守りの買い置きがあるから！","ENG":"I bought some charms from Madam Chloe Starseeker, and they're supposed to be good for nightmares!","TWN":"我有跟克洛伊·尋星夫人買消災解厄的符咒！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그런 사이비 부적은 절대로 안 쓸 거야!","JPN":"そんなインチキのお守りなんか絶対に使わない！","ENG":"I'm never using those shady charms!","TWN":"我才不會用那種冒牌的符咒！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그보다 라우라…….","JPN":"そんなことより、ラウラ……","ENG":"Anyway, Laura...","TWN":"不過蘿拉……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>최초의 인형</color> 말하려는 거지?","JPN":"<color=#ffd34c>最初の人形</color>のことだろう？","ENG":"I know. The <color=#ffd34c>Original Puppet</color>, right?","TWN":"你是想說<color=#ffd34c>最初的人偶</color>的事吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"역시 느꼈나 보네.","JPN":"やっぱり感じたのね。","ENG":"You must've felt it too, then.","TWN":"你果然也有感覺到。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그 힘이 어디로 흘러 가는지 계속 눈여겨보고 있었으니까.","JPN":"あの力がどこに向かっているのかずっと見てたからな。","ENG":"I was keeping an eye on where the energy was going.","TWN":"因為我一直在關注那股力量的流向。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"기척이 사라졌어. 죽은 걸까?","JPN":"気配が消えたわ。死んだのかしら？","ENG":"I can't sense her. Could she be dead?","TWN":"一點動靜都沒有，是死了嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그럴 리가. 어디 뒷방에 처박혀서 후일이나 도모하고 있겠지.","JPN":"そんなはずあるか。どこか奥に閉じこもって機会を狙っているんだろう。","ENG":"I doubt it. She's probably hiding in a corner somewhere, scheming something.","TWN":"怎麼可能，應該是躲在某個角落裡策劃著什麼吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"아무래도 좋으니, 그녀석이 숨죽이고 있을 때 우리도 빨리 힘을 길러 놔야 해. 특히 유나.","JPN":"それはともかく、奴が息をひそめている間に妾たちも早く力をつける必要がある。特にユナ。","ENG":"Wherever she is, we have to prepare ourselves while she's inactive. Especially Yuna.","TWN":"總之，趁她現在還沒有動作，我們要趕緊增加自己的實力，尤其是你，尤娜。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어? 나?","JPN":"えっ？　私？","ENG":"Huh? Me?","TWN":"什麼？我？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"견습 대마녀 주제에 마법 연습도 제대로 안 하고 뭐하는 거야?","JPN":"見習い大魔女のくせに、魔法の練習もしっかりやらずに何をしているんだ？","ENG":"What are you doing, fooling around, when you're the great witch-in-training!","TWN":"你一個見習大魔女，都沒好好練習魔法，是在做什麼？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"가, 갑자기?","JPN":"い、いきなり？","ENG":"W-what? Where did that come from?","TWN":"幹嘛突然說我？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"하루에 여섯 시간씩 꼬박꼬박 마법 연습 하라고 했지, 내가! 제대로 안 지켜?!","JPN":"1日に6時間、欠かさず魔法の練習をしろと言っただろう！　なぜ守らない！？","ENG":"I told you to practice magic six hours a day, didn't I?! Quit wasting time!","TWN":"我叫你每天練習六個小時的魔法！你以為我會放水嗎？！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"흐잉… 너무해, 라우라! 못됐어!","JPN":"ふえん……ひどいよ、ラウラ！　いじわる！","ENG":"Hng… Laura, you're so mean!","TWN":"嗚嗚……好壞喔，蘿拉好壞！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"아아, 그래. 그거야. 이제 좀 칭찬 듣는 기분이네.","JPN":"ああ、そう、それだ。やっと誉められた気になったな。","ENG":"Ahh, yes. That's it. Now that feels like a real compliment.","TWN":"哼哼，很好，現在聽起來像是對我的讚美呢。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"착해 빠진 공주따위보다야, 못돼먹은 마녀가 훨씬 기분 좋지. 안 그래, 플루토?","JPN":"優しいお姫様なんかより、性格の悪い魔女の方がよっぽど気分がいい。そう思わないか、プルートー？","ENG":"It's always better to be a mean old witch than a nice, gentle princess. Right, Pluto?","TWN":"與其做一個善良的公主，不如當個壞心眼的魔女，這樣還比較開心。對嗎，布魯托？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹!","JPN":"にゃあ！","ENG":"Meow!","TWN":"喵喵！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"둘 다 정말 너무해!!","JPN":"二人ともひどすぎる！！","ENG":"You're both so mean!!","TWN":"你們二個都很壞！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"}]`);export{e as default};